theme.styles:
/* MD3 role palette ([[md3Light]]/[[md3Dark]], late-bound). Body
   specificity + all three class states + declaration order: see the
   module doc for why each is required. */
body,body.light,body.dark{--primary:#006493;--on-primary:#ffffff;--primary-container:#cae6ff;--on-primary-container:#001e30;--secondary:#50606e;--on-secondary:#ffffff;--secondary-container:#d3e5f5;--on-secondary-container:#0c1d29;--tertiary:#65587b;--on-tertiary:#ffffff;--tertiary-container:#ebddff;--on-tertiary-container:#201634;--error:#ba1a1a;--on-error:#ffffff;--error-container:#ffdad6;--on-error-container:#410002;--background:#fcfcff;--on-background:#1a1c1e;--surface:#fcfcff;--on-surface:#1a1c1e;--surface-variant:#dde3ea;--on-surface-variant:#41474d;--outline:#72787e;--outline-variant:#c1c7ce;--shadow:#000000;--scrim:#000000;--inverse-surface:#2e3133;--inverse-on-surface:#f0f0f3;--inverse-primary:#8dcdff;--surface-dim:#d9dadd;--surface-bright:#f9f9fc;--surface-container-lowest:#ffffff;--surface-container-low:#f3f3f6;--surface-container:#edeef1;--surface-container-high:#e8e8eb;--surface-container-highest:#e2e2e5}
@media (prefers-color-scheme:dark){
  body,body.light,body.dark{--primary:#8dcdff;--on-primary:#00344f;--primary-container:#004b70;--on-primary-container:#cae6ff;--secondary:#b7c9d9;--on-secondary:#22323f;--secondary-container:#384956;--on-secondary-container:#d3e5f5;--tertiary:#cfc0e8;--on-tertiary:#362b4b;--tertiary-container:#4d4162;--on-tertiary-container:#ebddff;--error:#ffb4ab;--on-error:#690005;--error-container:#93000a;--on-error-container:#ffb4ab;--background:#1a1c1e;--on-background:#e2e2e5;--surface:#1a1c1e;--on-surface:#e2e2e5;--surface-variant:#41474d;--on-surface-variant:#c1c7ce;--outline:#8b9198;--outline-variant:#41474d;--shadow:#000000;--scrim:#000000;--inverse-surface:#e2e2e5;--inverse-on-surface:#2e3133;--inverse-primary:#006493;--surface-dim:#111416;--surface-bright:#37393c;--surface-container-lowest:#0c0e11;--surface-container-low:#1a1c1e;--surface-container:#1e2022;--surface-container-high:#282a2d;--surface-container-highest:#333537}
}
/* HA-token re-pointing — LAST so it wins in both schemes. Keeps the HA
   look on MD3: HA blue as primary, HA background/text/divider, and the
   card/dialog surfaces (article reads --surface-container-low, dialog
   --surface-container-high) on the HA card color. */
body,body.light,body.dark{
  --primary:var(--primary-color);
  --on-primary:var(--text-primary-color);
  --background:var(--primary-background-color);
  --surface:var(--primary-background-color);
  --on-background:var(--primary-text-color);
  --on-surface:var(--primary-text-color);
  --on-surface-variant:var(--secondary-text-color);
  --outline-variant:var(--divider-color);
  --error:var(--error-color);
  --surface-container-low:var(--card-background-color);
  --surface-container-high:var(--card-background-color);
}

/* Contract CSS BeerCSS doesn't cover (cards/buttons/dialogs/sliders it
   styles as elements). Layout containers, ported from theme.pkl. */
.fh-row{display:flex;gap:1rem;flex-wrap:wrap}
.fh-col{display:flex;flex-direction:column;gap:1rem}
.fh-row>.fh-col{flex:1 1 0;min-width:0;align-self:flex-start}
.fh-cell{display:contents}
.section{color:var(--primary)}
.state{color:var(--on-surface-variant)}
.entity .secondary{display:block;font-size:.8em;color:var(--on-surface-variant)}
.card.tappable{cursor:pointer}
/* Our Tabs container carries class `tabs`, which is ALSO a BeerCSS element
   class (row flex + bottom border + nowrap) — neutralize what leaks onto
   the fh-col wrapper. */
.fh-col.tabs{white-space:normal;border-block-end:none}
.tabbar{display:flex;gap:.5rem;flex-wrap:wrap}
.tabbar .tab{background:transparent;color:var(--on-surface);border:1px solid var(--outline-variant)}
.tabbar .tab.active{background:var(--primary);color:var(--on-primary);border-color:transparent}
.tab-panel{display:contents}

/* Popup: BeerCSS's <dialog> styling (fixed, centered, elevated,
   surface-container-high) does the chrome; cap the width and unfill the ✕
   (a bare <button> is a filled primary pill by default). */
dialog.popup{max-inline-size:min(90vw,32rem)}
.popup-close{position:absolute;top:.5rem;right:.5rem;background:transparent;
  color:var(--on-surface-variant);block-size:auto;padding:.25rem .5rem;font-size:1rem}
